const input = $input.first().json;
const query = input.query || input || {};
const baseUrl = String(process.env.NAVER_COMMERCE_API_BASE || 'https://api.commerce.naver.com/external').replace(/\/$/, '');
const accessToken = String(process.env.NAVER_COMMERCE_ACCESS_TOKEN || process.env.NAVER_COMMERCE_SELF_TOKEN || process.env.NAVER_COMMERCE_SELLER_TOKEN || '').trim();
if (!accessToken) {
  throw new Error('NAVER_COMMERCE_ACCESS_TOKEN 이 설정되지 않았습니다. 토큰 helper 또는 단기 캐시를 먼저 연결해야 합니다.');
}
function getParts(date) {
  const parts = new Intl.DateTimeFormat('en-US', {
    timeZone: 'Asia/Seoul',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hourCycle: 'h23',
  }).formatToParts(date);
  return Object.fromEntries(parts.filter((part) => part.type !== 'literal').map((part) => [part.type, part.value]));
}
function formatKstDate(date) {
  const parts = getParts(date);
  return `${parts.year}-${parts.month}-${parts.day}`;
}
function formatKstDateTime(date) {
  const parts = getParts(date);
  return `${parts.year}-${parts.month}-${parts.day}T${parts.hour}:${parts.minute}:${parts.second}+09:00`;
}
const now = new Date();
const customerEndDate = String(query.customerEndDate || formatKstDate(now)).trim();
const customerStartDate = String(query.customerStartDate || formatKstDate(new Date(now.getTime() - 6 * 24 * 60 * 60 * 1000))).trim();
const qnaToDate = String(query.qnaToDate || formatKstDateTime(now)).trim();
const qnaFromDate = String(query.qnaFromDate || formatKstDateTime(new Date(now.getTime() - 48 * 60 * 60 * 1000))).trim();
const customerQuery = String(query.customerQuery || '').trim();
const qnaQuery = String(query.qnaQuery || '').trim();
const onlyPendingRaw = String(query.onlyPending || 'true').trim().toLowerCase();
const onlyPending = onlyPendingRaw !== 'false';
const customerParams = customerQuery ? customerQuery : new URLSearchParams({
  startSearchDate: customerStartDate,
  endSearchDate: customerEndDate,
}).toString();
const qnaParams = qnaQuery ? qnaQuery : new URLSearchParams({
  fromDate: qnaFromDate,
  toDate: qnaToDate,
}).toString();
const customerUrl = `${baseUrl}/v1/pay-user/inquiries?${customerParams}`;
const qnaUrl = `${baseUrl}/v1/contents/qnas?${qnaParams}`;
return [{ json: {
  base_url: baseUrl,
  access_token: accessToken,
  customer_url: customerUrl,
  qna_url: qnaUrl,
  only_pending: onlyPending,
  customer_query: customerParams,
  qna_query: qnaParams,
  adapter_version: 'smartstore-adapter-v1',
} }];

function extractRecords(payload) {
  if (Array.isArray(payload)) return payload;
  if (payload && Array.isArray(payload.items)) return payload.items;
  if (payload && Array.isArray(payload.list)) return payload.list;
  if (payload && Array.isArray(payload.content)) return payload.content;
  if (payload && payload.data && Array.isArray(payload.data.items)) return payload.data.items;
  if (payload && payload.data && Array.isArray(payload.data.list)) return payload.data.list;
  if (payload && payload.contents && Array.isArray(payload.contents)) return payload.contents;
  return [];
}
function toIso(value) {
  if (!value) return new Date().toISOString();
  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? new Date().toISOString() : date.toISOString();
}
function maskName(value) {
  const text = String(value || '고객').trim();
  if (text.length <= 1) return text;
  if (text.includes('*')) return text;
  if (text.length === 2) return `${text[0]}*`;
  return `${text[0]}${'*'.repeat(Math.max(1, text.length - 2))}${text[text.length - 1]}`;
}
const request = $('요청 파라미터 정리').first().json;
const customerPayload = $('스마트스토어 고객 문의 조회').first().json;
const qnaPayload = $('스마트스토어 상품 문의 조회').first().json;
const customerItems = extractRecords(customerPayload).map((row) => ({
  id: String(row.inquiryNo ?? row.id ?? ''),
  orderId: String(row.orderId ?? ''),
  productId: String(row.productNo ?? row.productId ?? ''),
  productName: String(row.productName ?? ''),
  customerName: maskName(row.customerName ?? row.customerId ?? '고객'),
  subject: String(row.title ?? '고객 문의'),
  body: String(row.inquiryContent ?? row.body ?? ''),
  status: row.answered === true ? 'ANSWERED' : 'OPEN',
  receivedAt: toIso(row.inquiryRegistrationDateTime ?? row.receivedAt ?? row.createDate),
  url: '',
  sourceKind: 'customer_inquiry',
  answered: row.answered === true,
  rawCategory: String(row.category ?? ''),
  answerPreview: String(row.answerContent ?? ''),
})).filter((row) => row.id);
const qnaItems = extractRecords(qnaPayload).map((row) => ({
  id: `qna_${String(row.questionId ?? row.id ?? '')}`,
  orderId: '',
  productId: String(row.productId ?? row.productNo ?? ''),
  productName: String(row.productName ?? ''),
  customerName: maskName(row.maskedWriterId ?? row.customerName ?? '고객'),
  subject: '상품 문의',
  body: String(row.question ?? row.body ?? ''),
  status: row.answered === true ? 'ANSWERED' : 'OPEN',
  receivedAt: toIso(row.createDate ?? row.receivedAt),
  url: '',
  sourceKind: 'product_qna',
  answered: row.answered === true,
  rawCategory: '',
  answerPreview: String(row.answer ?? ''),
})).filter((row) => row.id !== 'qna_');
let items = [...customerItems, ...qnaItems];
if (request.only_pending) {
  items = items.filter((row) => row.status === 'OPEN');
}
items.sort((a, b) => new Date(a.receivedAt).getTime() - new Date(b.receivedAt).getTime());
return [{ json: {
  items,
  meta: {
    adapter: 'smartstore-inquiry-adapter-v1',
    onlyPending: request.only_pending,
    customerCount: customerItems.length,
    qnaCount: qnaItems.length,
    totalCount: items.length,
    customerQuery: request.customer_query,
    qnaQuery: request.qna_query,
  }
} }];
